urlset:

    {{ site_url }}/
    {% now "Y-m-d" %}
    weekly
    1.0


{% if portfolio_index %}

    {{ site_url }}{{ portfolio_index.url }}
    {% now "Y-m-d" %}
    weekly
    0.9

{% endif %}

{% for page in demo_pages %}

    {{ site_url }}{{ page.url }}
    {% if page.last_published_at %}{{ page.last_published_at|date:"Y-m-d" }}{% else %}{% now "Y-m-d" %}{% endif %}
    monthly
    0.8

{% endfor %}

{% if about_page %}

    {{ site_url }}{{ about_page.url }}
    {% if about_page.last_published_at %}{{ about_page.last_published_at|date:"Y-m-d" }}{% else %}{% now "Y-m-d" %}{% endif %}
    monthly
    0.7

{% endif %}

{% if blog_index %}

    {{ site_url }}{{ blog_index.url }}
    {% now "Y-m-d" %}
    weekly
    0.6

{% endif %}

{% for page in blog_pages %}

    {{ site_url }}{{ page.url }}
    {% if page.last_published_at %}{{ page.last_published_at|date:"Y-m-d" }}{% else %}{% now "Y-m-d" %}{% endif %}
    monthly
    0.5

{% endfor %}
